 1→export const getPostsCopy = (count) => {
 2→    if (count === 0) return 'The blank page is waiting';
 3→    if (count === 1) return 'A seed planted';
 4→    if (count >= 7) return 'Your most prolific week!';
 5→    if (count >= 3) return 'Building momentum';
 6→    return 'Off to a good start';
 7→};
 8→
 9→export const getWordsCopy = (count) => {
10→    if (!count || count === 0) return 'Every word counts';
11→    if (count >= 5000) return 'A chapter in the making';
12→    if (count >= 2000) return 'The ink is flowing';
13→    if (count >= 500) return 'Finding your rhythm';
14→    return 'First strokes on the canvas';
15→};
16→
17→export const getReactionsCopy = (count) => {
18→    if (!count || count === 0) return 'Your readers are out there';
19→    if (count >= 50) return 'Resonating deeply';
20→    if (count >= 20) return 'Striking a chord';
21→    if (count >= 5) return 'Sparking connection';
22→    return 'Making an impression';
23→};
24→
25→export const getViewsCopy = (count) => {
26→    if (!count || count === 0) return 'Eyes will follow';
27→    if (count >= 500) return 'Drawing a crowd';
28→    if (count >= 100) return 'Turning heads';
29→    if (count >= 20) return 'Catching attention';
30→    return 'First glances';
31→};
32→
33→export const getOverallEncouragement = (personal, streakCount) => {
34→    const posts = personal?.posts_written || 0;
35→
36→    if (streakCount >= 7) return "Don't break the streak — your consistency is paying off.";
37→    if (posts >= 7) return 'Prolific week — your readers can feel the momentum.';
38→    if (posts >= 3) return 'Solid pace this week. Keep the words flowing.';
39→    if (posts === 1) return 'You showed up. That matters more than you think.';
40→    if (posts === 0) return 'A quiet week, sometimes the best ideas need silence first.';
41→    return 'Your weekly writing at a glance.';
42→};
